import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
function homePage(){
    const name = (
        <div id = "main">
            <head>
                <title>React Sucks!</title>
            </head>
            <div>
            <body>
                <h3>Hello React!</h3>
                <h3>The time is: {new Date().toLocaleTimeString()}.</h3>
            </body>
            </div>
        </div>
    );
    ReactDOM.render(name, document.getElementById('root'))
}
setInterval(homePage, 0.01)
